                    _unsafeWriteBytesOffset(output, outputLength++, HEX_DIGITS[char & 0x0f]);
                }
            } else {
                _unsafeWriteBytesOffset(output, outputLength++, bytes1(char));
            }
        }
        // write the actual length and reserve memory
        assembly ("memory-safe") {
            mstore(output, outputLength)
            mstore(0x40, add(output, add(outputLength, 0x20)))
        }

        return string(output);
    }

    /**
     * @dev Reads a bytes32 from a bytes array without bounds checking.
     *
     * NOTE: making this function internal would mean it could be used with memory unsafe offset, and marking the
     * assembly block as such would prevent some optimizations.
     */
    function _unsafeReadBytesOffset(bytes memory buffer, uint256 offset) private pure returns (bytes32 value) {
        // This is not memory safe in the general case, but all calls to this private function are within bounds.
        assembly ("memory-safe") {
            value := mload(add(add(buffer, 0x20), offset))
        }
    }

    /**
     * @dev Write a bytes1 to a bytes array without bounds checking.
     *
     * NOTE: making this function internal would mean it could be used with memory unsafe offset, and marking the
     * assembly block as such would prevent some optimizations.
     */
    function _unsafeWriteBytesOffset(bytes memory buffer, uint256 offset, bytes1 value) private pure {
        // This is not memory safe in the general case, but all calls to this private function are within bounds.
        assembly ("memory-safe") {
            mstore8(add(add(buffer, 0x20), offset), shr(248, value))
        }
    }
}

contracts/CertificateLifecycle.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/utils/Pausable.sol";
import "./RoleManager.sol";
import "./RevocationRegistry.sol";

/**
 * @title CertificateLifecycle
 * @dev Tracks the entire lifecycle of a certificate, including multisig approvals
 */
contract CertificateLifecycle is Pausable {
    enum DocState { DRAFT, UNDER_REVIEW, APPROVED, SIGNED, ISSUED, REVOKED }

    struct Certificate {
        bytes32 docHash;          // IPFS hash of document
        DocState state;           // current state
        address issuedTo;         // citizen's wallet / DID
        address createdBy;        // officer who drafted
        address[] approvers;      // all who approved
        uint256[] stateTimestamps; // timestamp of every state change
        string metadataURI;       // IPFS URI of full document metadata
        bool isRevoked;
    }

    struct ApprovalConfig {
        uint256 requiredApprovals;    // e.g., 2 out of 3 must approve
        address[] designatedApprovers;
        uint256 approvalCount;
    }

    RoleManager public roleManager;
    RevocationRegistry public revocationRegistry;

    mapping(bytes32 => Certificate) public certificates;
    mapping(bytes32 => ApprovalConfig) public certificateApprovals;
    
    // Mapping to track if an address has approved a specific docHash
    mapping(bytes32 => mapping(address => bool)) public hasApproved;

    event CertificateStateChanged(bytes32 indexed docHash, DocState newState, address changedBy, uint256 timestamp);

    constructor(address _roleManager, address _revocationRegistry) {
        roleManager = RoleManager(_roleManager);
        revocationRegistry = RevocationRegistry(_revocationRegistry);
    }

    modifier onlyOfficer() {
        require(
            roleManager.hasRole(roleManager.ISSUER_OFFICER_ROLE(), msg.sender),
            "CertificateLifecycle: Must be ISSUER_OFFICER"
        );
        _;
    }

    modifier onlyApprover() {
        require(
            roleManager.hasRole(roleManager.APPROVER_ROLE(), msg.sender),
            "CertificateLifecycle: Must be APPROVER"
        );
        _;
    }

    modifier checkRevocation(bytes32 docHash) {
        if (revocationRegistry.isRevoked(docHash)) {
            Certificate storage cert = certificates[docHash];
            if (!cert.isRevoked) {
                cert.isRevoked = true;
                cert.state = DocState.REVOKED;
                cert.stateTimestamps.push(block.timestamp);
                emit CertificateStateChanged(docHash, DocState.REVOKED, msg.sender, block.timestamp);
            }
        }
        require(!certificates[docHash].isRevoked, "CertificateLifecycle: Certificate is revoked");
        _;
    }

    /**
     * @dev Create a new DRAFT certificate
     */
    function createDraft(
        bytes32 docHash,
        address issuedTo,
        string calldata metadataURI,
        uint256 requiredApprovals,
        address[] calldata designatedApprovers
    ) external onlyOfficer whenNotPaused {
        require(certificates[docHash].stateTimestamps.length == 0, "CertificateLifecycle: Certificate already exists");
        
        Certificate storage cert = certificates[docHash];
        cert.docHash = docHash;
        cert.state = DocState.DRAFT;
        cert.issuedTo = issuedTo;
        cert.createdBy = msg.sender;
        cert.metadataURI = metadataURI;
        cert.isRevoked = false;
        cert.stateTimestamps.push(block.timestamp);

        ApprovalConfig storage config = certificateApprovals[docHash];
        config.requiredApprovals = requiredApprovals;
        config.designatedApprovers = designatedApprovers;
        
        emit CertificateStateChanged(docHash, DocState.DRAFT, msg.sender, block.timestamp);
    }

    /**
     * @dev Submit DRAFT for review
     */
    function submitForReview(bytes32 docHash) external onlyOfficer whenNotPaused checkRevocation(docHash) {
        Certificate storage cert = certificates[docHash];
        require(cert.createdBy == msg.sender, "CertificateLifecycle: Only creator can submit");
        require(cert.state == DocState.DRAFT, "CertificateLifecycle: Must be in DRAFT state");
        
        cert.state = DocState.UNDER_REVIEW;
        cert.stateTimestamps.push(block.timestamp);

        emit CertificateStateChanged(docHash, DocState.UNDER_REVIEW, msg.sender, block.timestamp);
    }

    /**
     * @dev Approve a certificate
     */
    function approveCertificate(bytes32 docHash) external onlyApprover whenNotPaused checkRevocation(docHash) {
        Certificate storage cert = certificates[docHash];
        require(cert.state == DocState.UNDER_REVIEW, "CertificateLifecycle: Must be UNDER_REVIEW");
        
        ApprovalConfig storage config = certificateApprovals[docHash];
        
        bool isDesignated = false;
        for (uint i = 0; i < config.designatedApprovers.length; i++) {
            if (config.designatedApprovers[i] == msg.sender) {
                isDesignated = true;
                break;
            }
        }
        require(isDesignated, "CertificateLifecycle: Not a designated approver");
        require(!hasApproved[docHash][msg.sender], "CertificateLifecycle: Already approved");

        hasApproved[docHash][msg.sender] = true;
        config.approvalCount++;
        cert.approvers.push(msg.sender);

        if (config.approvalCount >= config.requiredApprovals) {
            cert.state = DocState.APPROVED;
            cert.stateTimestamps.push(block.timestamp);
            emit CertificateStateChanged(docHash, DocState.APPROVED, msg.sender, block.timestamp);
        }
    }

    /**
     * @dev Sign the approved certificate
     */
    function signCertificate(bytes32 docHash) external onlyApprover whenNotPaused checkRevocation(docHash) {
        Certificate storage cert = certificates[docHash];
        require(cert.state == DocState.APPROVED, "CertificateLifecycle: Must be APPROVED");
        
        cert.state = DocState.SIGNED;
        cert.stateTimestamps.push(block.timestamp);

        emit CertificateStateChanged(docHash, DocState.SIGNED, msg.sender, block.timestamp);
    }

    /**
     * @dev Issue the signed certificate
     */
    function issueCertificate(bytes32 docHash) external onlyOfficer whenNotPaused checkRevocation(docHash) {
        Certificate storage cert = certificates[docHash];
        require(cert.state == DocState.SIGNED, "CertificateLifecycle: Must be SIGNED");
        
        cert.state = DocState.ISSUED;
        cert.stateTimestamps.push(block.timestamp);

        emit CertificateStateChanged(docHash, DocState.ISSUED, msg.sender, block.timestamp);
    }
    
    /**
     * @dev Manually Sync Revocation status from the external registry (since it can happen asynchronously)
     */
    function syncRevocation(bytes32 docHash) external {
        if (revocationRegistry.isRevoked(docHash)) {
            Certificate storage cert = certificates[docHash];
            require(cert.stateTimestamps.length > 0, "Lifecycle: Certificate does not exist");
            if (!cert.isRevoked) {
                cert.isRevoked = true;
                cert.state = DocState.REVOKED;
                cert.stateTimestamps.push(block.timestamp);
                emit CertificateStateChanged(docHash, DocState.REVOKED, msg.sender, block.timestamp);
            }
        }
    }

    /**
     * @dev Get certificate basic info
     */
    function getCertificate(bytes32 docHash) external view returns (Certificate memory) {
        return certificates[docHash];
    }
}

contracts/CredentialRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/utils/cryptography/EIP712.sol";
import "@openzeppelin/contracts/utils/cryptography/ECDSA.sol";
import "./RoleManager.sol";

/**
 * @title CredentialRegistry
 * @dev Issues, verifies, and revokes credentials.
 *      Uses EIP-712 typed data signing so the ISSUER must sign each credential —
 *      the server wallet CANNOT issue on someone else's behalf.
 */
contract CredentialRegistry is EIP712 {
    RoleManager public roleManager;

    bytes32 public constant CREDENTIAL_TYPEHASH = keccak256(
        "Credential(address subject,string credentialType,string metadataURI,uint256 expirationDate)"
    );

    struct Credential {
        address issuer;
        address subject;
        string credentialType;
        string metadataURI;     // ipfs://CID of document metadata
        uint256 issuedAt;
        uint256 expirationDate; // 0 = no expiry
        bool revoked;
    }

    // credentialId => Credential
    mapping(bytes32 => Credential) public credentials;
    // subject => list of credentialIds
    mapping(address => bytes32[]) public credentialsBySubject;
    // issuer => list of credentialIds
    mapping(address => bytes32[]) public credentialsByIssuer;
    // Dev Rep Scores (kept here for backward compat with CredentialRegistry usage)
    mapping(address => uint256) public devRepScores;

    event CredentialIssued(
        bytes32 indexed credentialId,
        address indexed issuer,
        address indexed subject,
        string credentialType
    );
    event CredentialRevoked(bytes32 indexed credentialId, address indexed issuer);
    event IssuerAuthorized(address indexed issuer);
    event RepScoreUpdated(address indexed user, uint256 newScore);

    constructor(address _roleManager)
        EIP712("CredoraRegistry", "1")
    {
        roleManager = RoleManager(_roleManager);
    }

    modifier onlyAuthorizedIssuer() {
        require(
            roleManager.hasRole(roleManager.ISSUER_OFFICER_ROLE(), msg.sender),
            "CredentialRegistry: Must be ISSUER_OFFICER"
        );
        _;
    }

    /**
     * @dev Issue a credential with EIP-712 signature verification.
     *      The issuer must sign the credential data from their own wallet (MetaMask).
     *      The server cannot issue on behalf of anyone.
     *
     * @param subject          Wallet of the credential recipient
     * @param credentialType   e.g. "UniversityDegree", "BootcampCert"
     * @param metadataURI      IPFS URI of document metadata JSON
     * @param expirationDate   Unix timestamp, 0 = never expires
     * @param signature        EIP-712 signature from the issuer's wallet
     */
    function issueCredential(
        address subject,
        string calldata credentialType,
        string calldata metadataURI,
        uint256 expirationDate,
        bytes calldata signature
    ) external onlyAuthorizedIssuer returns (bytes32 credentialId) {
        // Verify the issuer actually signed this data from their own MetaMask
        require(
            _verifyIssuerSignature(subject, credentialType, metadataURI, expirationDate, signature),
            "CredentialRegistry: Invalid issuer signature"
        );

        // Unique ID from all credential fields
        credentialId = keccak256(
            abi.encodePacked(msg.sender, subject, credentialType, metadataURI, block.timestamp)
        );
        require(credentials[credentialId].issuedAt == 0, "CredentialRegistry: Already exists");

        credentials[credentialId] = Credential({
            issuer: msg.sender,
            subject: subject,
            credentialType: credentialType,
            metadataURI: metadataURI,
            issuedAt: block.timestamp,
            expirationDate: expirationDate,
            revoked: false
        });

        credentialsBySubject[subject].push(credentialId);
        credentialsByIssuer[msg.sender].push(credentialId);

        emit CredentialIssued(credentialId, msg.sender, subject, credentialType);
    }

    /**
     * @dev Revoke a credential. Only the original issuer can revoke.
     */
    function revokeCredential(bytes32 credentialId) external {
        Credential storage cred = credentials[credentialId];
        require(cred.issuedAt != 0, "CredentialRegistry: Does not exist");
        require(cred.issuer == msg.sender, "CredentialRegistry: Only issuer can revoke");
        require(!cred.revoked, "CredentialRegistry: Already revoked");
        cred.revoked = true;
        emit CredentialRevoked(credentialId, msg.sender);
    }

    /**
     * @dev Verify a credential directly on-chain.
     */
    function verifyCredential(bytes32 credentialId) external view returns (
        bool isValid,
        bool isExpired,
        bool isRevoked,
        address issuer,
        address subject,
        string memory credentialType,
        uint256 issuedAt
    ) {
        Credential memory cred = credentials[credentialId];
        bool expired = cred.expirationDate != 0 && block.timestamp > cred.expirationDate;
        return (
            cred.issuedAt != 0 && !cred.revoked && !expired,
            expired,
            cred.revoked,
            cred.issuer,
            cred.subject,
            cred.credentialType,
            cred.issuedAt
        );
    }

    /**
     * @dev Get all credential IDs for a given subject (wallet).
     */
    function getCredentialsBySubject(address subject) external view returns (bytes32[] memory) {
        return credentialsBySubject[subject];
    }

    /**
     * @dev Get a single credential struct.
     */
    function getCredential(bytes32 credentialId) external view returns (Credential memory) {
        return credentials[credentialId];
    }

    /**
     * @dev Legacy: check if issuer is authorized by checking if they have ISSUER_OFFICER_ROLE.
     */
    function checkIssuer(address issuer) external view returns (bool) {
        return roleManager.hasRole(roleManager.ISSUER_OFFICER_ROLE(), issuer);
    }

    /**
     * @dev Update Dev Rep Score — called by server wallet after computing score from GitHub.
     */
    function updateRepScore(address user, uint256 repos, uint256 badges, uint256 multiplier)
        external
    {
        require(
            roleManager.hasRole(roleManager.ISSUER_OFFICER_ROLE(), msg.sender) ||
            roleManager.hasRole(roleManager.ADMIN_ROLE(), msg.sender),
            "CredentialRegistry: Not authorized to update rep score"
        );
        uint256 score = (repos + badges) * multiplier;
        devRepScores[user] = score;
        emit RepScoreUpdated(user, score);
    }

    // ─── Internal ────────────────────────────────────────────────────────────

    function _verifyIssuerSignature(
        address subject,
        string calldata credentialType,
        string calldata metadataURI,
        uint256 expirationDate,
        bytes calldata signature
    ) internal view returns (bool) {
        bytes32 structHash = keccak256(abi.encode(
            CREDENTIAL_TYPEHASH,
            subject,
            keccak256(bytes(credentialType)),
            keccak256(bytes(metadataURI)),
            expirationDate
        ));
        bytes32 digest = _hashTypedDataV4(structHash);
        address recovered = ECDSA.recover(digest, signature);
        return recovered == msg.sender;
    }
}

contracts/RevocationRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "./RoleManager.sol";

/**
 * @title RevocationRegistry
 * @dev On-chain revocation registry. Only ADMINs can revoke.
 *      Stores full reason + revoker + timestamp for audit trails.
 */
contract RevocationRegistry {
    RoleManager public roleManager;

    struct RevocationRecord {
        string reason;
        address revokedBy;
        uint256 timestamp;
        bool exists;
    }

    mapping(bytes32 => RevocationRecord) public revocations;

    event CertificateRevoked(bytes32 indexed docHash, string reason, address indexed revokedBy, uint256 timestamp);

    constructor(address _roleManager) {
        roleManager = RoleManager(_roleManager);
    }

    modifier onlyAdmin() {
        require(
            roleManager.hasRole(roleManager.ADMIN_ROLE(), msg.sender),
            "RevocationRegistry: Must be ADMIN"
        );
        _;
    }

    /**
     * @dev Revoke a certificate by its docHash.
     * @param docHash  The document hash (bytes32 from keccak256 or sha256)
     * @param reason   Human-readable reason for revocation
     */
    function revoke(bytes32 docHash, string memory reason) external onlyAdmin {
        require(!revocations[docHash].exists, "RevocationRegistry: Already revoked");
        revocations[docHash] = RevocationRecord({
            reason: reason,
            revokedBy: msg.sender,
            timestamp: block.timestamp,
            exists: true
        });
        emit CertificateRevoked(docHash, reason, msg.sender, block.timestamp);
    }

    /**
     * @dev Check if a credential is revoked.
     */
    function isRevoked(bytes32 docHash) external view returns (bool) {
        return revocations[docHash].exists;
    }

    /**
     * @dev Get full revocation details. Used by frontend useRevocation hook.
     */
    function getRevocationDetails(bytes32 docHash) external view returns (
        string memory reason,
        address revokedBy,
        uint256 timestamp
    ) {
        RevocationRecord memory r = revocations[docHash];
        require(r.exists, "RevocationRegistry: Not revoked");
        return (r.reason, r.revokedBy, r.timestamp);
    }
}

